import React, { useState, useCallback } from 'react';
import { ImagePlus, Zap, Download, FileArchive, CheckCircle2, X } from 'lucide-react';

interface ImageCompressorProps {}

export const ImageCompressor: React.FC<ImageCompressorProps> = () => {
  const [files, setFiles] = useState<File[]>([]);
  const [isDragging, setIsDragging] = useState(false);
  const [compressing, setCompressing] = useState(false);
  const [progress, setProgress] = useState(0);
  const [status, setStatus] = useState('');
  const [compressedZipUrl, setCompressedZipUrl] = useState<string | null>(null);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles = Array.from(e.target.files).filter(f => f.type.startsWith('image/'));
      setFiles(prev => [...prev, ...newFiles]);
      setCompressedZipUrl(null);
    }
  };

  const onDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const droppedFiles = Array.from(e.dataTransfer.files).filter(f => f.type.startsWith('image/'));
    setFiles(prev => [...prev, ...droppedFiles]);
    setCompressedZipUrl(null);
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
    setCompressedZipUrl(null);
  };

  const compressAndZip = async () => {
    if (files.length === 0 || compressing) return;

    const JSZip = (window as any).JSZip;
    if (!JSZip) {
      alert("جاري تحميل المكتبات، يرجى المحاولة بعد قليل.");
      return;
    }

    setCompressing(true);
    setProgress(0);
    setStatus('بدء عملية الضغط...');

    const zip = new JSZip();
    const quality = 0.6; // 60% quality for significant size reduction

    try {
      for (let i = 0; i < files.length; i++) {
        const file = files[i];
        setStatus(`جاري معالجة: ${file.name}`);

        const compressedBlob = await new Promise<Blob>((resolve, reject) => {
          const reader = new FileReader();
          reader.readAsDataURL(file);
          reader.onload = (event) => {
            const img = new Image();
            img.src = event.target?.result as string;
            img.onload = () => {
              const canvas = document.createElement('canvas');
              const ctx = canvas.getContext('2d');

              // Maintain aspect ratio, but maybe cap max dimension if needed for performance
              let width = img.width;
              let height = img.height;

              canvas.width = width;
              canvas.height = height;
              ctx?.drawImage(img, 0, 0, width, height);

              canvas.toBlob(
                (blob) => {
                  if (blob) resolve(blob);
                  else reject(new Error('Canvas toBlob failed'));
                },
                'image/jpeg',
                quality
              );
            };
          };
          reader.onerror = reject;
        });

        const fileName = file.name.substring(0, file.name.lastIndexOf('.')) || file.name;
        zip.file(`${fileName}_compressed.jpg`, compressedBlob);

        const currentProgress = Math.round(((i + 1) / files.length) * 100);
        setProgress(currentProgress);
      }

      setStatus('جاري إنشاء ملف الـ ZIP النهائي...');
      const content = await zip.generateAsync({ type: 'blob' });
      const url = URL.createObjectURL(content);
      setCompressedZipUrl(url);
      setStatus('اكتملت العملية بنجاح!');
    } catch (err) {
      console.error(err);
      setStatus('حدث خطأ أثناء الضغط.');
    } finally {
      setCompressing(false);
    }
  };

  return (
    <div className="bg-slate-900 border border-slate-800 rounded-3xl overflow-hidden shadow-2xl flex flex-col md:flex-row min-h-[400px]">
      {/* Left Side: Upload Area */}
      <div 
        className={`flex-1 p-8 flex flex-col items-center justify-center border-l border-slate-800 transition-all duration-300
          ${isDragging ? 'bg-indigo-600/10' : 'bg-slate-900'}`}
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={onDrop}
      >
        <input 
          id="image-input" 
          type="file" 
          multiple 
          accept="image/*" 
          className="hidden" 
          onChange={handleFileSelect} 
        />

        <div 
          onClick={() => document.getElementById('image-input')?.click()}
          className="bg-slate-800 p-6 rounded-3xl mb-6 cursor-pointer hover:scale-105 transition-transform shadow-xl border border-slate-700"
        >
          <ImagePlus size={48} className="text-indigo-500" />
        </div>

        <h2 className="text-xl font-bold mb-2 text-white">ضاغط الصور الاحترافي</h2>
        <p className="text-slate-400 text-center text-xs mb-6 max-w-[250px]">
          ارفع صورك (حتى 300 صورة) لضغط حجمها بنسبة تصل إلى 70% مع الحفاظ على الجودة.
        </p>

        {files.length > 0 && !compressing && !compressedZipUrl && (
          <button 
            onClick={compressAndZip}
            className="flex items-center gap-2 px-8 py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-bold text-sm transition-all active:scale-95 shadow-lg shadow-indigo-600/20"
          >
            <Zap size={18} />
            بدء ضغط {files.length} صورة
          </button>
        )}

        {compressing && (
          <div className="w-full max-w-[250px] space-y-3">
             <div className="flex justify-between items-end">
                <span className="text-[10px] text-slate-500 font-bold uppercase">{status}</span>
                <span className="text-lg font-black text-indigo-400">{progress}%</span>
             </div>
             <div className="h-2 bg-slate-800 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-indigo-500 transition-all duration-300" 
                  style={{ width: `${progress}%` }}
                ></div>
             </div>
          </div>
        )}

        {compressedZipUrl && (
          <a 
            href={compressedZipUrl}
            download="FlexStudio_Compressed_Images.zip"
            className="flex items-center gap-2 px-8 py-3 bg-green-600 hover:bg-green-500 text-white rounded-2xl font-bold text-sm transition-all active:scale-95 shadow-lg shadow-green-600/20 animate-bounce"
          >
            <Download size={18} />
            تحميل ملف ZIP المضغوط
          </a>
        )}
      </div>

      {/* Right Side: Files List */}
      <div className="w-full md:w-80 bg-slate-950/50 p-6 flex flex-col">
        <div className="flex items-center justify-between mb-4 border-b border-slate-800 pb-3">
           <h3 className="text-xs font-bold text-slate-400 flex items-center gap-2">
             <FileArchive size={14} />
             قائمة الملفات ({files.length})
           </h3>
           {files.length > 0 && (
             <button 
               onClick={() => { setFiles([]); setCompressedZipUrl(null); }} 
               className="text-[10px] text-red-400 hover:underline"
             >
               مسح الكل
             </button>
           )}
        </div>

        <div className="flex-1 overflow-y-auto max-h-[300px] md:max-h-none space-y-2 custom-scrollbar">
          {files.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center opacity-20 py-10">
               <FileArchive size={32} />
               <p className="text-[10px] mt-2">لا توجد ملفات</p>
            </div>
          ) : (
            files.map((file, idx) => (
              <div key={idx} className="flex items-center gap-3 p-2 bg-slate-800/40 rounded-xl border border-slate-800/50 group">
                <div className="w-8 h-8 rounded-lg bg-slate-700 flex items-center justify-center text-[8px] font-bold overflow-hidden">
                  <img src={URL.createObjectURL(file)} className="w-full h-full object-cover" />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-[10px] font-medium text-slate-300 truncate">{file.name}</p>
                  <p className="text-[8px] text-slate-500">{(file.size / 1024).toFixed(1)} KB</p>
                </div>
                <button onClick={() => removeFile(idx)} className="opacity-0 group-hover:opacity-100 p-1 text-slate-500 hover:text-red-400 transition-all">
                  <X size={14} />
                </button>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { Header } from './components/Header';
import { SVGAViewer } from './components/SVGAViewer';
import { DropZone } from './components/DropZone';
import { ImageCompressor } from './components/ImageCompressor';
import { SVGAFileInfo } from './types';
import { FolderUp, History, Info, Image as ImageIcon, Box } from 'lucide-react';

interface SVGAFileExtended extends SVGAFileInfo {
  rawFile?: File;
}

const App: React.FC = () => {
  const [currentFile, setCurrentFile] = useState<SVGAFileExtended | null>(null);
  const [history, setHistory] = useState<SVGAFileExtended[]>([]);

  const handleFileUpload = useCallback((file: File) => {
    const url = URL.createObjectURL(file);
    const fileInfo: SVGAFileExtended = {
      name: file.name,
      size: file.size,
      type: file.type,
      lastModified: file.lastModified,
      url: url,
      rawFile: file
    };

    setCurrentFile(fileInfo);
    setHistory(prev => {
      const filtered = prev.filter(p => p.name !== fileInfo.name);
      return [fileInfo, ...filtered.slice(0, 9)];
    });
  }, []);

  const formatSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-950 text-right pb-10" dir="rtl">
      <Header />

      <main className="flex-1 container mx-auto px-4 py-8">
        {!currentFile ? (
          <div className="flex flex-col gap-12">
            {/* SVGA Section */}
            <section>
              <div className="flex items-center gap-3 mb-6">
                 <div className="p-2 bg-blue-500/10 rounded-lg">
                    <Box className="text-blue-500" size={20} />
                 </div>
                 <h2 className="text-xl font-bold text-white">عارض ملفات SVGA</h2>
              </div>

              <div className="flex flex-col lg:flex-row gap-8">
                <div className="flex-1">
                  <div className="bg-slate-900 border border-slate-800 rounded-3xl overflow-hidden shadow-2xl">
                    <DropZone onFileSelect={handleFileUpload} />
                  </div>
                </div>

                <div className="w-full lg:w-80">
                  <div className="bg-slate-900/50 border border-slate-800 rounded-2xl p-6 h-full min-h-[400px]">
                    <div className="flex items-center justify-between mb-6">
                      <div className="flex items-center gap-2 text-blue-400">
                        <History size={20} />
                        <h2 className="font-bold text-lg">السجل</h2>
                      </div>
                    </div>

                    {history.length > 0 ? (
                      <div className="flex flex-col gap-3">
                        {history.map((item, idx) => (
                          <button
                            key={`${item.name}-${idx}`}
                            onClick={() => setCurrentFile(item)}
                            className="flex items-center gap-3 p-3 rounded-xl border border-transparent bg-slate-800/40 hover:border-slate-700 text-slate-300 transition-all text-right group"
                          >
                            <div className="bg-slate-800 p-2 rounded-lg group-hover:bg-slate-700">
                              <FolderUp size={16} className="text-blue-400" />
                            </div>
                            <div className="flex-1 min-w-0">
                              <p className="text-sm font-medium truncate">{item.name}</p>
                              <p className="text-[10px] text-slate-500">{formatSize(item.size)}</p>
                            </div>
                          </button>
                        ))}
                      </div>
                    ) : (
                      <div className="flex flex-col items-center justify-center text-slate-500 py-20">
                        <History size={40} className="mb-4 opacity-20" />
                        <p className="text-xs">السجل فارغ</p>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </section>

            {/* Image Compressor Section */}
            <section>
               <div className="flex items-center gap-3 mb-6">
                 <div className="p-2 bg-indigo-500/10 rounded-lg">
                    <ImageIcon className="text-indigo-500" size={20} />
                 </div>
                 <h2 className="text-xl font-bold text-white">ضاغط الصور الجماعي (Bulk)</h2>
              </div>
              <ImageCompressor />
            </section>
          </div>
        ) : (
          <div className="flex flex-col gap-8">
            <div className="bg-slate-900 border border-slate-800 rounded-3xl overflow-hidden shadow-2xl">
              <SVGAViewer 
                file={currentFile} 
                onClear={() => setCurrentFile(null)} 
                originalFile={currentFile.rawFile}
              />
            </div>

            <div className="bg-slate-900/50 border border-slate-800 rounded-2xl p-6 backdrop-blur-sm">
              <div className="flex items-center gap-3 mb-4 text-slate-400">
                <Info size={18} />
                <h3 className="font-semibold text-xs uppercase tracking-wider">خصائص ملف الرسوم</h3>
              </div>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                <div>
                  <p className="text-[10px] text-slate-500 mb-1 uppercase">اسم الملف</p>
                  <p className="text-sm font-bold truncate text-white">{currentFile.name}</p>
                </div>
                <div>
                  <p className="text-[10px] text-slate-500 mb-1 uppercase">حجم البيانات</p>
                  <p className="text-sm font-bold text-white">{formatSize(currentFile.size)}</p>
                </div>
                <div>
                  <p className="text-[10px] text-slate-500 mb-1 uppercase">التنسيق</p>
                  <p className="text-sm font-bold text-blue-400">Flex Engine v2.0</p>
                </div>
                <div>
                  <p className="text-[10px] text-slate-500 mb-1 uppercase">آخر تحديث</p>
                  <p className="text-sm font-bold text-white">
                    {new Date(currentFile.lastModified).toLocaleDateString('ar-EG', { day: 'numeric', month: 'long' })}
                  </p>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="py-8 border-t border-slate-900 text-center">
         <p className="text-xs text-slate-600 font-medium">تم التطوير بواسطة فليكس - Flex Studio Pro 2026</p>
      </footer>
    </div>
  );
};

export default App;

