      const newFiles = Array.from(e.target.files).filter((f: File) => f.type.startsWith('image/')) as File[];
      setFiles(prev => [...prev, ...newFiles]);
      setCompressedZipUrl(null);
    }
  };

  const onDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const droppedFiles = Array.from(e.dataTransfer.files).filter((f: File) => f.type.startsWith('image/')) as File[];
    setFiles(prev => [...prev, ...droppedFiles]);
    setCompressedZipUrl(null);
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
    setCompressedZipUrl(null);
  };

  const compressAndZip = async () => {
    if (files.length === 0 || compressing) return;

    const JSZip = (window as any).JSZip;
    if (!JSZip) {
      alert("جاري تحميل المكتبات، يرجى المحاولة بعد قليل.");
      return;
    }

    setCompressing(true);
    setProgress(0);
    setStatus('تحليل الصور والحفاظ على الشفافية...');

    const zip = new JSZip();

    // جودة مرتفعة للحفاظ على التفاصيل (85%)
    const quality = 0.85; 

    try {
      for (let i = 0; i < files.length; i++) {
        const file = files[i];
        setStatus(`جاري معالجة: ${file.name}`);

        const compressedBlob = await new Promise<Blob>((resolve, reject) => {
          const reader = new FileReader();
          reader.readAsDataURL(file);
          reader.onload = (event) => {
            const img = new Image();
            img.src = event.target?.result as string;
            img.onload = () => {
              const canvas = document.createElement('canvas');
              const ctx = canvas.getContext('2d');

              if (!ctx) {
                reject(new Error('Failed to get canvas context'));
                return;
              }

              canvas.width = img.width;
              canvas.height = img.height;

              // مسح الكانفاس لضمان الشفافية للصور التي تدعمها (مثل PNG)
              ctx.clearRect(0, 0, canvas.width, canvas.height);
              ctx.drawImage(img, 0, 0);

              // تحديد التنسيق المناسب بناءً على الملف الأصلي للحفاظ على الشفافية
              // إذا كانت الصورة PNG أو WebP، نحافظ على التنسيق. إذا كانت JPG، نضغطها كـ JPG.
              let mimeType = file.type;

              // في حال كانت الصورة PNG، نستخدم PNG للحفاظ على الشفافية
              // ملاحظة: PNG لا يدعم معامل الجودة في toBlob ببعض المتصفحات، لكن إعادة الرسم تقلل الحجم غالباً
              canvas.toBlob(
                (blob) => {
                  if (blob) resolve(blob);
                  else reject(new Error('Canvas toBlob failed'));
                },
                mimeType,
                mimeType === 'image/jpeg' || mimeType === 'image/webp' ? quality : undefined
              );
            };
          };
          reader.onerror = reject;
        });

        zip.file(file.name, compressedBlob);

        const currentProgress = Math.round(((i + 1) / files.length) * 100);
        setProgress(currentProgress);
      }

      setStatus('تجميع الملفات في أرشيف واحد...');
      const content = await zip.generateAsync({ type: 'blob' });
      const url = URL.createObjectURL(content);
      setCompressedZipUrl(url);
      setStatus('اكتملت العملية مع الحفاظ على الشفافية!');
    } catch (err) {
      console.error(err);
      setStatus('حدث خطأ أثناء المعالجة الذكية.');
    } finally {
      setCompressing(false);
    }
  };

