        onDrop={onDrop}
      >
        <input 
          id="image-input" 
          type="file" 
          multiple 
          accept="image/*" 
          className="hidden" 
          onChange={handleFileSelect} 
        />

        <div 
          onClick={() => document.getElementById('image-input')?.click()}
          className="bg-slate-800 p-6 rounded-3xl mb-6 cursor-pointer hover:scale-105 transition-transform shadow-xl border border-slate-700 relative group"
        >
          <ImagePlus size={48} className="text-indigo-500" />
          <div className="absolute -top-2 -right-2 bg-green-500 p-1.5 rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-opacity">
            <ShieldCheck size={14} className="text-white" />
          </div>
        </div>

        <h2 className="text-xl font-bold mb-2 text-white">ضاغط الصور الذكي</h2>
        <p className="text-slate-400 text-center text-xs mb-2 max-w-[280px]">
          تخفيف حجم الصور مع الحفاظ على <span className="text-indigo-400 font-bold">الجودة الأصلية</span> و <span className="text-indigo-400 font-bold">الخلفية الشفافة</span>.
        </p>
        <div className="flex gap-2 mb-6">
           <span className="px-2 py-0.5 bg-slate-800 rounded-md text-[9px] text-slate-500 font-bold border border-slate-700">PNG Transparent</span>
           <span className="px-2 py-0.5 bg-slate-800 rounded-md text-[9px] text-slate-500 font-bold border border-slate-700">High Quality JPG</span>
        </div>

        {files.length > 0 && !compressing && !compressedZipUrl && (
          <button 
            onClick={compressAndZip}
            className="flex items-center gap-2 px-8 py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-bold text-sm transition-all active:scale-95 shadow-lg shadow-indigo-600/20"
          >
            <Zap size={18} />
            بدء معالجة {files.length} صورة
          </button>
        )}

        {compressing && (
          <div className="w-full max-w-[250px] space-y-3">
             <div className="flex justify-between items-end">
                <span className="text-[10px] text-slate-500 font-bold uppercase truncate max-w-[180px]">{status}</span>
                <span className="text-lg font-black text-indigo-400">{progress}%</span>
             </div>
             <div className="h-2 bg-slate-800 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-indigo-500 transition-all duration-300" 
                  style={{ width: `${progress}%` }}
                ></div>
             </div>
          </div>
        )}

        {compressedZipUrl && (
          <div className="flex flex-col items-center gap-3 animate-in fade-in zoom-in duration-500">
            <div className="flex items-center gap-2 text-green-400 text-xs font-bold mb-2">
              <CheckCircle2 size={16} />
              تم الحفاظ على الشفافية والجودة
            </div>
            <a 
              href={compressedZipUrl}
              download="FlexStudio_Compressed_Images.zip"
              className="flex items-center gap-2 px-8 py-3 bg-green-600 hover:bg-green-500 text-white rounded-2xl font-bold text-sm transition-all active:scale-95 shadow-lg shadow-green-600/20"
            >
              <Download size={18} />
              تحميل الملف (ZIP)
            </a>
            <button 
               onClick={() => { setFiles([]); setCompressedZipUrl(null); }} 
               className="text-[10px] text-slate-500 hover:text-white transition-colors"
            >
              إلغاء المعالجة والبدء من جديد
            </button>
          </div>
        )}
      </div>

      {/* Right Side: Files List */}
      <div className="w-full md:w-80 bg-slate-950/50 p-6 flex flex-col">
        <div className="flex items-center justify-between mb-4 border-b border-slate-800 pb-3">
           <h3 className="text-xs font-bold text-slate-400 flex items-center gap-2">
             <FileArchive size={14} />
             قائمة الصور ({files.length})
           </h3>
           {files.length > 0 && (
             <button 
               onClick={() => { setFiles([]); setCompressedZipUrl(null); }} 
               className="text-[10px] text-red-400 hover:underline"
             >
               مسح الكل
             </button>
           )}
        </div>

        <div className="flex-1 overflow-y-auto max-h-[300px] md:max-h-none space-y-2 custom-scrollbar pr-1">
          {files.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center opacity-20 py-10">
               <FileArchive size={32} />
               <p className="text-[10px] mt-2">اسحب الصور هنا</p>
            </div>
          ) : (
            files.map((file, idx) => (
              <div key={idx} className="flex items-center gap-3 p-2 bg-slate-800/40 rounded-xl border border-slate-800/50 group">
                <div className="w-8 h-8 rounded-lg bg-slate-700 flex items-center justify-center text-[8px] font-bold overflow-hidden relative">
